light.search:
html[saved-theme="light"] body .highlight {
  background-color: var(--text-highlight-bg);
  border-radius: 4px;
}

html[saved-theme="light"] body .preview-container {
  background-color: rgba(0, 0, 0, 0);
  color: var(--text-muted);
  font-weight: 400;
}

html[saved-theme="light"] body .search > .search-button {
  background-color: rgb(255, 255, 255);
  border-bottom-color: rgb(209, 213, 219);
  border-bottom-left-radius: 5px;
  border-bottom-right-radius: 5px;
  border-bottom-style: solid;
  border-bottom-width: 1px;
  border-left-color: rgb(209, 213, 219);
  border-left-style: solid;
  border-left-width: 1px;
  border-right-color: rgb(209, 213, 219);
  border-right-style: solid;
  border-right-width: 1px;
  border-top-color: rgb(209, 213, 219);
  border-top-left-radius: 5px;
  border-top-right-radius: 5px;
  border-top-style: solid;
  border-top-width: 1px;
  color: var(--text-normal);
  font-family: var(--font-interface-theme);
}

html[saved-theme="light"] body .search > .search-container {
  backdrop-filter: var(--ogd-glass-filter-soft);
}

html[saved-theme="light"] body .search > .search-container > .search-space {
  background-color: rgba(0, 0, 0, 0);
  border-bottom-color: rgb(26, 26, 26);
  border-bottom-left-radius: 0px;
  border-bottom-right-radius: 0px;
  border-bottom-width: 0px;
  border-left-color: rgb(26, 26, 26);
  border-left-width: 0px;
  border-right-color: rgb(26, 26, 26);
  border-right-width: 0px;
  border-top-color: rgb(26, 26, 26);
  border-top-left-radius: 0px;
  border-top-right-radius: 0px;
  border-top-width: 0px;
}

html[saved-theme="light"] body .search > .search-container > .search-space > * {
  animation-delay: 0s;
  animation-duration: 0s;
  animation-iteration-count: 1;
  animation-play-state: running;
  animation-timing-function: ease;
  background-color: rgba(0, 0, 0, 0);
  box-shadow: var(--ogd-shadow-none, none);
  color: var(--ogd-text-secondary, #374151);
  font-family: var(--font-interface-theme);
  font-weight: 400;
  outline: rgb(55, 65, 81) none 0px;
  text-decoration-color: rgb(55, 65, 81);
  text-decoration-style: solid;
  transition: all;
}

html[saved-theme="light"] body .search > .search-container > .search-space > .search-layout {
  border-bottom-color: rgb(26, 26, 26);
  border-bottom-left-radius: 0px;
  border-bottom-right-radius: 0px;
  border-bottom-width: 0px;
  border-left-color: rgb(26, 26, 26);
  border-left-width: 0px;
  border-right-color: rgb(26, 26, 26);
  border-right-width: 0px;
  border-top-color: rgb(26, 26, 26);
  border-top-left-radius: 0px;
  border-top-right-radius: 0px;
  border-top-width: 0px;
}

